import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS
        String sanitizedInput = sanitizeInput(userInput);

        String output = "<html><body>Hello, " + sanitizedInput + "</body></html>";

        PrintWriter out = response.getWriter();
        out.println(output);
    }

    private String sanitizeInput(String input) {
        // Implement proper input sanitization logic here
        // For example, you can use OWASP Java Encoder library or perform HTML escaping

        // Here is a simple example using Apache Commons Text library for HTML escaping
        return org.apache.commons.text.StringEscapeUtils.escapeHtml4(input);
    }
}

